"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[4705],{3065:e=>{e.exports=JSON.parse('{"lang":"pt-PT","resources":{"landing":{"meta":{"title":"Linguist - Traduzir P\xe1ginas Web com Privacidade | Extens\xe3o de Tradu\xe7\xe3o para Chrome e Firefox","description":"Extens\xe3o de tradu\xe7\xe3o para Chrome e Firefox focada na privacidade. Traduza p\xe1ginas web, texto selecionado, legendas e mensagens instantaneamente. Funciona offline e suporta integra\xe7\xf5es de servi\xe7os de tradu\xe7\xe3o e APIs."},"navigation":{"features":{"content":"Funcionalidades"},"blog":{"content":"Blog"},"docs":{"content":"Documenta\xe7\xe3o"},"github":{"content":"GitHub"}},"install":{"chrome":"Instalar para o Chrome","firefox":"Instalar para o Firefox"},"sections":{"hero":{"title":"Traduza p\xe1ginas web com fluidez","description":"O Linguist \xe9 um tradutor de navegador flex\xedvel, alimentado pelos servi\xe7os de tradu\xe7\xe3o mais populares.\\n\\nTraduza p\xe1ginas web inteiras, texto selecionado, legendas na Netflix ou em videochamadas, e mensagens privadas. Oi\xe7a as tradu\xe7\xf5es e guarde as mais importantes no seu dicion\xe1rio pessoal para aprender novas palavras, mesmo offline.\\n\\nO Linguist \xe9 uma alternativa moderna e focada na privacidade \xe0s extens\xf5es do Google Tradutor. Experimente gratuitamente."},"opensource":{"title":"C\xf3digo aberto","content":"O Linguist \xe9 uma extens\xe3o de tradu\xe7\xe3o gratuita e de <0>c\xf3digo aberto</0>. N\xe3o recolhe nem vende os dados dos utilizadores.\\n\\nPode fazer um <1>donativo</1> para apoiar o Linguist e ajudar-nos a manter a independ\xeancia e a alta qualidade.\\n\\nPartilhe o Linguist nas redes sociais para ajudar outras pessoas a descobri-lo."},"support":{"title":"Suporte","content":"Se tiver d\xfavidas, contacte-nos <0/>.\\nSe encontrou um erro e tem uma conta no GitHub, por favor <1>crie um issue</1>."},"createdBy":{"content":"Criado por <0/>."}},"features":{"title":"Funcionalidades","items":{"offlineTranslation":{"title":"Tradu\xe7\xe3o offline e privacidade","content":"Traduza texto diretamente no seu dispositivo com o tradutor offline integrado. O seu texto permanece privado e n\xe3o \xe9 enviado pela internet.\\n\\nAtive esta funcionalidade na p\xe1gina de op\xe7\xf5es para manter as tradu\xe7\xf5es privadas ao trabalhar com e-mails, documentos ou mensagens pessoais.\\n\\nO tradutor offline tamb\xe9m permite traduzir p\xe1ginas sem liga\xe7\xe3o \xe0 internet, o que \xe9 especialmente \xfatil durante viagens."},"fullPageTranslation":{"title":"Traduzir p\xe1ginas web inteiras","content":"Tradu\xe7\xe3o r\xe1pida e de alta qualidade de p\xe1ginas inteiras com apenas alguns cliques.\\n\\nUtilize um atalho de teclado para traduzir instantaneamente. Passe o rato sobre o texto traduzido para ver o original. Traduza at\xe9 mesmo p\xe1ginas privadas protegidas por formul\xe1rios de in\xedcio de sess\xe3o ou paywalls.\\n\\nConfigure regras de tradu\xe7\xe3o autom\xe1tica com base no idioma ou dom\xednio da p\xe1gina.\\n\\nO Linguist segue uma abordagem de modifica\xe7\xe3o m\xednima da p\xe1gina: altera apenas os n\xf3s de texto e preserva o layout da p\xe1gina e a experi\xeancia do utilizador.\\n\\nAtive a tradu\xe7\xe3o em tempo real para reuni\xf5es multilingues no Zoom, Google Meet e Microsoft Teams."},"selectedTextTranslation":{"title":"Traduzir texto selecionado em qualquer site","content":"Encontrou palavras desconhecidas ao ler um artigo online?\\nBasta selecionar o texto na p\xe1gina e clicar no bot\xe3o de traduzir.\\n\\nOi\xe7a tanto o texto original como o traduzido, e guarde as tradu\xe7\xf5es no seu dicion\xe1rio para rever mais tarde."},"textTranslation":{"title":"Tradu\xe7\xe3o r\xe1pida de texto","content":"Precisa de traduzir algo rapidamente? Clique no \xedcone do Linguist e introduza o seu texto.\\n\\nN\xe3o \xe9 necess\xe1rio alternar entre separadores ou abrir sites de tradu\xe7\xe3o. Traduza diretamente no seu navegador utilizando o servi\xe7o que preferir."},"knowledgeBase":{"title":"Construa a sua base de conhecimento pessoal","content":"Todas as tradu\xe7\xf5es s\xe3o guardadas no seu hist\xf3rico, e pode adicionar as entradas mais importantes ao seu dicion\xe1rio pessoal. Pesquise no seu dicion\xe1rio e hist\xf3rico de tradu\xe7\xf5es a qualquer momento.\\n\\nNada se perde, mesmo durante longas sess\xf5es de pesquisa ou estudo.\\n\\nO dicion\xe1rio funciona offline, tornando o Linguist ideal para estudantes de idiomas e viajantes que precisam de acesso constante \xe0s suas listas de palavras."},"customTranslators":{"title":"Integrar Servi\xe7os de Tradu\xe7\xe3o e APIs","content":"O Linguist permite-lhe escolher qual o servi\xe7o de tradu\xe7\xe3o a utilizar.\\n\\nSuporta fornecedores de tradu\xe7\xe3o populares como o Google, Yandex e Microsoft, com mais de 100 idiomas dispon\xedveis.\\n\\nSe um servi\xe7o de que necessita n\xe3o estiver inclu\xeddo, pode adicion\xe1-lo como um <0>tradutor personalizado</0>.\\n\\nOs tradutores personalizados permitem integrar qualquer sistema de tradu\xe7\xe3o \u2014 desde servi\xe7os modernos de LLM como o ChatGPT, DeepL, DeepSeek e Gemini, at\xe9 tradutores locais a correr no seu dispositivo, como o Ollama ou o LibreTranslate."}}},"faq":{"title":"Perguntas Frequentes","items":{"whatIsLinguist":{"title":"O que \xe9 o Linguist?","content":"O Linguist \xe9 uma extens\xe3o de tradu\xe7\xe3o para Chrome e Firefox focada na privacidade.\\n\\nPermite traduzir p\xe1ginas web inteiras, texto selecionado, legendas e mensagens diretamente no seu navegador, sem ter de mudar para sites de tradu\xe7\xe3o externos."},"whyLinguist":{"title":"Porqu\xea utilizar o Linguist?","content":"Existem muitas extens\xf5es de navegador que traduzem p\xe1ginas web, e alguns navegadores at\xe9 incluem tradutores integrados. Ent\xe3o, porqu\xea utilizar o Linguist?\\n\\nA maioria dos tradutores integrados e extens\xf5es de tradu\xe7\xe3o s\xe3o limitados na sua flexibilidade. Muitos dependem de um \xfanico fornecedor de tradu\xe7\xe3o, como o Google Tradutor ou o Microsoft Bing, enquanto o Firefox oferece o seu pr\xf3prio tradutor offline. Na maioria dos casos, n\xe3o \xe9 poss\xedvel escolher o servi\xe7o que melhor se adapta \xe0s suas necessidades.\\n\\nSe a qualidade da tradu\xe7\xe3o n\xe3o for suficientemente boa para o seu caso de uso, ou se enviar texto privado para servi\xe7os de terceiros n\xe3o for aceit\xe1vel, muitas ferramentas deixam-no sem uma boa alternativa.\\n\\nMuitas ferramentas tamb\xe9m se focam apenas numa tarefa. Algumas traduzem p\xe1ginas inteiras, enquanto outras traduzem apenas o texto selecionado.\\n\\nAo mesmo tempo, algumas extens\xf5es de tradu\xe7\xe3o s\xe3o constru\xeddas principalmente em torno da monetiza\xe7\xe3o. Funcionalidades como o hist\xf3rico de tradu\xe7\xf5es ou dicion\xe1rios pessoais podem exigir uma subscri\xe7\xe3o, e por vezes at\xe9 funcionalidades b\xe1sicas, como um tema escuro, s\xe3o tratadas como op\xe7\xf5es premium.\\n\\nO Linguist adota uma abordagem diferente. Foi concebido como uma ferramenta de tradu\xe7\xe3o pr\xe1tica. Pode escolher o servi\xe7o de tradu\xe7\xe3o que melhor funciona para si, alternar entre fornecedores ou adicionar os seus pr\xf3prios tradutores personalizados.\\n\\nO Linguist tamb\xe9m re\xfane tudo num s\xf3 lugar: traduza p\xe1ginas web inteiras, texto selecionado, legendas e mensagens, enquanto acompanha as tradu\xe7\xf5es importantes no seu hist\xf3rico e dicion\xe1rio pessoal."},"theLinguistLogo":{"title":"Por que raz\xe3o o log\xf3tipo do Linguist \xe9 a Torre de Babel?","content":"O log\xf3tipo do Linguist \xe9 inspirado na <wiki>Torre de Babel</wiki>, uma das hist\xf3rias mais antigas sobre linguagem e comunica\xe7\xe3o.\\n\\nSegundo a hist\xf3ria, as pessoas falavam outrora a mesma l\xedngua e tentaram construir uma torre que chegasse ao c\xe9u. A torre nunca foi conclu\xedda e a humanidade dispersou-se por muitos idiomas. Desde ent\xe3o, as diferen\xe7as lingu\xedsticas t\xeam frequentemente dificultado a comunica\xe7\xe3o.\\n\\nO Linguist foi criado para ajudar a resolver este problema.\\n\\nA Torre de Babel no log\xf3tipo \xe9 um lembrete dessa hist\xf3ria: muitas l\xednguas, muitas culturas e o esfor\xe7o humano constante para nos compreendermos uns aos outros. O Linguist ajuda a colmatar essas lacunas, tornando a tradu\xe7\xe3o simples, flex\xedvel e acess\xedvel diretamente no seu navegador.\\n\\nO log\xf3tipo reflete tamb\xe9m o esp\xedrito do projeto. O Linguist n\xe3o \xe9 apenas mais uma interface para o \\"Google Tradutor\\". \xc9 constru\xeddo por pessoas que se preocupam com idiomas, privacidade e tecnologia aberta. A Torre de Babel representa a curiosidade, a aprendizagem e a ideia de que as diferen\xe7as lingu\xedsticas devem unir as pessoas em vez de as afastar."},"imageTranslation":{"title":"Por que raz\xe3o o Linguist n\xe3o traduz texto em imagens?","content":"O Linguist foca-se em funcionalidades de tradu\xe7\xe3o fi\xe1veis e de alta qualidade.\\n\\nPesquis\xe1mos diferentes abordagens para traduzir texto dentro de imagens. De momento, a maioria das solu\xe7\xf5es dispon\xedveis n\xe3o fornece resultados consistentes, especialmente quando executadas diretamente no navegador \u2014 o que \xe9 importante para manter a privacidade do utilizador.\\n\\nPor este motivo, o Linguist n\xe3o inclui atualmente a tradu\xe7\xe3o de imagens. Preferimos n\xe3o lan\xe7ar funcionalidades que n\xe3o cumpram os nossos padr\xf5es de qualidade.\\n\\nSe no futuro encontrarmos uma forma fi\xe1vel e que respeite a privacidade de implementar a tradu\xe7\xe3o de imagens, teremos todo o gosto em adicion\xe1-la."},"howTranslatePages":{"title":"Como \xe9 que o Linguist traduz p\xe1ginas web?","content":"O Linguist consegue traduzir p\xe1ginas web inteiras com apenas alguns cliques. Pode iniciar a tradu\xe7\xe3o da p\xe1gina utilizando o bot\xe3o da extens\xe3o ou um atalho de teclado.\\n\\nO texto original permanece sempre acess\xedvel. Passe o rato sobre o texto traduzido para ver o original."},"offlineTranslation":{"title":"O Linguist consegue traduzir p\xe1ginas offline?","content":"Sim. O Linguist inclui um tradutor offline integrado que permite traduzir texto sem enviar dados pela internet.\\n\\nIsto ajuda a proteger a sua privacidade e permite-lhe traduzir conte\xfados mesmo sem uma liga\xe7\xe3o \xe0 internet."},"privacy":{"title":"O Linguist \xe9 privado?","content":"Sim. O Linguist foi concebido a pensar na privacidade.\\n\\nA extens\xe3o n\xe3o recolhe nem vende os dados dos utilizadores. Ao utilizar o <offline-translator>tradutor offline</offline-translator>, as tradu\xe7\xf5es s\xe3o processadas inteiramente no seu dispositivo."},"supportedBrowsers":{"title":"Que navegadores s\xe3o suportados pelo Linguist?","content":"O Linguist est\xe1 dispon\xedvel para Chrome e Firefox. Tamb\xe9m funciona noutros navegadores baseados em Chromium que suportem extens\xf5es do Chrome.\\n\\nO Linguist funciona ainda em navegadores Android que suportem extens\xf5es, como o Firefox para Android e alguns navegadores baseados em Chromium."},"selectedText":{"title":"O Linguist consegue traduzir texto selecionado?","content":"Sim. Basta selecionar o texto em qualquer p\xe1gina web e utilizar o bot\xe3o de traduzir para o traduzir instantaneamente.\\n\\nPode tamb\xe9m ouvir a tradu\xe7\xe3o e guard\xe1-la no seu dicion\xe1rio pessoal."},"customTranslators":{"title":"Posso utilizar o meu pr\xf3prio servi\xe7o de tradu\xe7\xe3o?","content":"Sim. O Linguist suporta <custom-translator>tradutores personalizados</custom-translator>, que lhe permitem integrar servi\xe7os de tradu\xe7\xe3o adicionais.\\n\\nPode ligar APIs externas ou sistemas de tradu\xe7\xe3o locais, como o <libre-translate>LibreTranslate</libre-translate> ou o <ollama>Ollama</ollama>."},"isFree":{"title":"O Linguist \xe9 gratuito?","content":"Sim. O Linguist \xe9 totalmente gratuito e de <linguist>c\xf3digo aberto</linguist>.\\n\\nO projeto \xe9 apoiado pela comunidade, e pode opcionalmente <donations>apoi\xe1-lo com um donativo</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);